3_real_world_example.code:
class Shape {
  draw() { console.log('Drawing a generic shape'); }
}

class Circle extends Shape {
  draw() { console.log('Drawing a round circle 🟢'); } // Overriding!
}

class Square extends Shape {
  draw() { console.log('Drawing a square 🟦'); } // Overriding!
}

const shapes = [new Circle(), new Square(), new Shape()];

// Polymorphism in action: We don't check 'if (shape is Circle)'. 
// We just tell them all to draw(), and they figure it out themselves.
shapes.forEach(shape => shape.draw());
// 'Drawing a round circle 🟢'
// 'Drawing a square 🟦'
// 'Drawing a generic shape'

